/**
 * Result Type
 *
 * Rust/Go-inspired Result type for explicit error handling.
 * Alternative to throwing errors or returning tuples.
 */
export type Result<T, E = Error> = {
    success: true;
    value: T;
    error: null;
} | {
    success: false;
    value: null;
    error: E;
};
/**
 * Create a successful result
 */
export declare function ok<T, E = Error>(value: T): Result<T, E>;
/**
 * Create an error result
 */
export declare function err<T, E = Error>(error: E): Result<T, E>;
/**
 * Unwrap result value or throw error
 */
export declare function unwrap<T, E = Error>(result: Result<T, E>): T;
/**
 * Unwrap result value or return default
 */
export declare function unwrapOr<T, E = Error>(result: Result<T, E>, defaultValue: T): T;
/**
 * Map result value if successful
 */
export declare function map<T, U, E = Error>(result: Result<T, E>, fn: (value: T) => U): Result<U, E>;
/**
 * Map result error if failed
 */
export declare function mapError<T, E, F>(result: Result<T, E>, fn: (error: E) => F): Result<T, F>;
